"use client"

import { useEffect, useMemo } from "react"
import { useChartContext } from "./chart-context"
import { xCenter } from "./scales"

export type XAxisProps = {
  dataKey: string
  tickFormatter?: (value: string | number) => string
  maxTicks?: number
}

export type YAxisProps = {
  tickFormatter?: (value: string | number) => string
  tickCount?: number
}

function pickTicks<T>(items: T[], max: number): T[] {
  if (items.length <= max) return items
  const step = Math.ceil(items.length / max)
  return items.filter((_, i) => i % step === 0)
}

export function XAxis({
  dataKey,
  tickFormatter = (v) => String(v),
  maxTicks = 8,
}: XAxisProps) {
  const { data, plot, xScale, xAxis, setXAxis } = useChartContext()

  useEffect(() => {
    setXAxis({ dataKey, tickFormatter, maxTicks })
  }, [dataKey, tickFormatter, maxTicks, setXAxis])

  const ticks = useMemo(() => {
    const domain = data.map((d) => String(d[dataKey] ?? ""))
    return pickTicks(domain, maxTicks)
  }, [data, dataKey, maxTicks])

  const y = plot.y + plot.height

  return (
    <g className="engrave-x-axis">
      <line
        x1={plot.x}
        x2={plot.x + plot.width}
        y1={y}
        y2={y}
        stroke="var(--foreground, #181816)"
        strokeWidth={1}
        opacity={0.35}
      />
      {ticks.map((label) => {
        const x = xCenter(xScale, label)
        return (
          <g key={label} transform={`translate(${x}, ${y})`}>
            <line y2={4} stroke="var(--foreground, #181816)" strokeWidth={1} opacity={0.35} />
            <text
              y={16}
              textAnchor="middle"
              className="fill-[var(--muted-foreground,#6b7280)] text-[10px]"
            >
              {xAxis.tickFormatter(label)}
            </text>
          </g>
        )
      })}
    </g>
  )
}

export function YAxis({
  tickFormatter = (v) => String(v),
  tickCount = 5,
}: YAxisProps) {
  const { plot, yScale, yAxis, setYAxis } = useChartContext()

  useEffect(() => {
    setYAxis({ tickFormatter, tickCount })
  }, [tickFormatter, tickCount, setYAxis])

  const ticks = useMemo(() => yScale.ticks(tickCount), [yScale, tickCount])

  return (
    <g className="engrave-y-axis">
      <line
        x1={plot.x}
        x2={plot.x}
        y1={plot.y}
        y2={plot.y + plot.height}
        stroke="var(--foreground, #181816)"
        strokeWidth={1}
        opacity={0.35}
      />
      {ticks.map((tick) => {
        const y = yScale(tick)
        return (
          <g key={tick} transform={`translate(${plot.x}, ${y})`}>
            <line x2={-4} stroke="var(--foreground, #181816)" strokeWidth={1} opacity={0.35} />
            <text
              x={-8}
              dy="0.32em"
              textAnchor="end"
              className="fill-[var(--muted-foreground,#6b7280)] text-[10px]"
            >
              {yAxis.tickFormatter(tick)}
            </text>
          </g>
        )
      })}
    </g>
  )
}

"use client"

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from "react"
import type { ScaleBand, ScaleLinear, ScalePoint } from "d3-scale"
import type { EngraveColor } from "./palette"
import {
  DEFAULT_MARGINS,
  createXBandScale,
  createXPointScale,
  createYLinearScale,
  plotRect,
  yExtent,
  type ChartDatum,
  type Margins,
  type PlotRect,
  type StackType,
} from "./scales"

export type SeriesKind = "area" | "line" | "bar"

export type SeriesEntry = {
  dataKey: string
  kind: SeriesKind
}

export type SeriesConfigEntry = {
  label?: string
  color?: EngraveColor
}

export type ChartConfig = Record<string, SeriesConfigEntry>

export type AxisTickFormatter = (value: string | number) => string

export type XAxisState = {
  dataKey: string
  tickFormatter: AxisTickFormatter
  maxTicks: number
}

export type YAxisState = {
  tickFormatter: AxisTickFormatter
  tickCount: number
}

export type ChartKind = "area" | "line" | "bar"

export type ChartContextValue = {
  data: ChartDatum[]
  config: ChartConfig
  stackType: StackType
  margins: Margins
  width: number
  height: number
  plot: PlotRect
  chartKind: ChartKind
  animate: boolean
  xScale: ScaleBand<string> | ScalePoint<string>
  yScale: ScaleLinear<number, number>
  xAxis: XAxisState
  yAxis: YAxisState
  series: SeriesEntry[]
  registerSeries: (entry: SeriesEntry) => void
  unregisterSeries: (dataKey: string) => void
  setXAxis: (axis: Partial<XAxisState>) => void
  setYAxis: (axis: Partial<YAxisState>) => void
  hoverIndex: number | null
  setHoverIndex: (index: number | null) => void
  selectedIndex: number | null
  setSelectedIndex: (index: number | null) => void
}

const ChartContext = createContext<ChartContextValue | null>(null)

const DEFAULT_X_AXIS: XAxisState = {
  dataKey: "name",
  tickFormatter: (v) => String(v),
  maxTicks: 8,
}

const DEFAULT_Y_AXIS: YAxisState = {
  tickFormatter: (v) => String(v),
  tickCount: 5,
}

export type ChartProviderProps = {
  data: ChartDatum[]
  config?: ChartConfig
  stackType?: StackType
  margins?: Partial<Margins>
  width: number
  height: number
  chartKind: ChartKind
  animate?: boolean
  children: ReactNode
}

export function ChartProvider({
  data,
  config = {},
  stackType = "default",
  margins: marginOverrides,
  width,
  height,
  chartKind,
  animate = true,
  children,
}: ChartProviderProps) {
  const margins = useMemo(
    () => ({ ...DEFAULT_MARGINS, ...marginOverrides }),
    [marginOverrides]
  )

  const [series, setSeries] = useState<SeriesEntry[]>([])
  const [xAxis, setXAxisState] = useState<XAxisState>(DEFAULT_X_AXIS)
  const [yAxis, setYAxisState] = useState<YAxisState>(DEFAULT_Y_AXIS)
  const [hoverIndex, setHoverIndex] = useState<number | null>(null)
  const [selectedIndex, setSelectedIndex] = useState<number | null>(null)

  const registerSeries = useCallback((entry: SeriesEntry) => {
    setSeries((prev) => {
      if (prev.some((s) => s.dataKey === entry.dataKey)) return prev
      return [...prev, entry]
    })
  }, [])

  const unregisterSeries = useCallback((dataKey: string) => {
    setSeries((prev) => prev.filter((s) => s.dataKey !== dataKey))
  }, [])

  const setXAxis = useCallback((axis: Partial<XAxisState>) => {
    setXAxisState((prev) => ({ ...prev, ...axis }))
  }, [])

  const setYAxis = useCallback((axis: Partial<YAxisState>) => {
    setYAxisState((prev) => ({ ...prev, ...axis }))
  }, [])

  const plot = useMemo(
    () => plotRect(width, height, margins),
    [width, height, margins]
  )

  const seriesKeys = useMemo(() => series.map((s) => s.dataKey), [series])

  const xRange = useMemo(
    (): [number, number] => [plot.x, plot.x + plot.width],
    [plot.x, plot.width]
  )

  const yRange = useMemo(
    (): [number, number] => [plot.y + plot.height, plot.y],
    [plot.y, plot.height]
  )

  const xScale = useMemo(() => {
    if (chartKind === "line") {
      return createXPointScale(data, xAxis.dataKey, xRange)
    }
    return createXBandScale(data, xAxis.dataKey, xRange)
  }, [chartKind, data, xAxis.dataKey, xRange])

  const yScale = useMemo(() => {
    const extent = yExtent(data, seriesKeys, stackType)
    return createYLinearScale(extent, yRange)
  }, [data, seriesKeys, stackType, yRange])

  const value = useMemo<ChartContextValue>(
    () => ({
      data,
      config,
      stackType,
      margins,
      width,
      height,
      plot,
      chartKind,
      animate,
      xScale,
      yScale,
      xAxis,
      yAxis,
      series,
      registerSeries,
      unregisterSeries,
      setXAxis,
      setYAxis,
      hoverIndex,
      setHoverIndex,
      selectedIndex,
      setSelectedIndex,
    }),
    [
      data,
      config,
      stackType,
      margins,
      width,
      height,
      plot,
      chartKind,
      animate,
      xScale,
      yScale,
      xAxis,
      yAxis,
      series,
      registerSeries,
      unregisterSeries,
      setXAxis,
      setYAxis,
      hoverIndex,
      selectedIndex,
    ]
  )

  return (
    <ChartContext.Provider value={value}>{children}</ChartContext.Provider>
  )
}

export function useChartContext(): ChartContextValue {
  const ctx = useContext(ChartContext)
  if (!ctx) {
    throw new Error("engrave-kit: chart components must be used inside a chart root")
  }
  return ctx
}

"use client"

import type { ReactNode } from "react"
import { ChartProvider, type ChartConfig, type ChartKind } from "./chart-context"
import { EngraveCanvas } from "./engrave-canvas"
import { useChartDimensions } from "./use-chart-dimensions"
import type { ChartDatum, Margins, StackType } from "./scales"

export type ChartShellProps = {
  data: ChartDatum[]
  config?: ChartConfig
  stackType?: StackType
  margins?: Partial<Margins>
  animate?: boolean
  className?: string
  chartKind: ChartKind
  children: ReactNode
}

export function ChartShell({
  data,
  config,
  stackType,
  margins,
  animate = true,
  className = "",
  chartKind,
  children,
}: ChartShellProps) {
  const { ref, width, height } = useChartDimensions<HTMLDivElement>()

  return (
    <ChartProvider
      data={data}
      config={config}
      stackType={stackType}
      margins={margins}
      width={width}
      height={height}
      chartKind={chartKind}
      animate={animate}
    >
      <div
        ref={ref}
        className={`relative h-64 w-full ${className}`.trim()}
      >
        <EngraveCanvas />
        <svg
          className="pointer-events-none absolute inset-0 h-full w-full overflow-visible"
          width={width}
          height={height}
        >
          {children}
        </svg>
      </div>
    </ChartProvider>
  )
}

"use client"

import type { ReactNode } from "react"
import { ChartShell, type ChartShellProps } from "./chart-shell"

type RootProps = Omit<ChartShellProps, "chartKind" | "children"> & {
  children: ReactNode
}

export function AreaChart(props: RootProps) {
  return <ChartShell {...props} chartKind="area" />
}

export function LineChart(props: RootProps) {
  return <ChartShell {...props} chartKind="line" />
}

export function BarChart(props: RootProps) {
  return <ChartShell {...props} chartKind="bar" />
}

"use client"

import { useCallback, useEffect, useRef } from "react"
import type { ScaleBand, ScalePoint } from "d3-scale"
import { useChartContext } from "./chart-context"
import {
  anglesForSeries,
  backingSize,
  easeOutCubic,
  hatch,
  prefersReducedMotion,
  toneBlock,
} from "./engrave-paint"
import { resolveColor } from "./palette"
import {
  stackSeries,
  valueAtIndex,
  xCenter,
  type ChartDatum,
} from "./scales"

const REVEAL_MS = 900

function numeric(d: ChartDatum, key: string): number {
  const v = d[key]
  return typeof v === "number" && Number.isFinite(v) ? v : 0
}

function indexAtX(
  data: ChartDatum[],
  xKey: string,
  xScale: ScaleBand<string> | ScalePoint<string>,
  px: number
): number {
  let best = 0
  let bestDist = Infinity
  for (let i = 0; i < data.length; i++) {
    const label = String(data[i][xKey] ?? "")
    const cx = xCenter(xScale, label)
    const dist = Math.abs(cx - px)
    if (dist < bestDist) {
      bestDist = dist
      best = i
    }
  }
  return best
}

export function EngraveCanvas() {
  const canvasRef = useRef<HTMLCanvasElement | null>(null)
  const rafRef = useRef<number | null>(null)
  const startRef = useRef<number | null>(null)
  const progressRef = useRef(1)

  const ctx = useChartContext()
  const {
    width,
    height,
    plot,
    data,
    series,
    config,
    stackType,
    chartKind,
    xScale,
    yScale,
    xAxis,
    animate,
    setHoverIndex,
  } = ctx

  const drawFrame = useCallback(
    (reveal: number) => {
      const canvas = canvasRef.current
      if (!canvas || width <= 0 || height <= 0 || series.length === 0) return

      const { width: bw, height: bh, dpr } = backingSize(width, height)
      canvas.width = bw
      canvas.height = bh
      canvas.style.width = `${width}px`
      canvas.style.height = `${height}px`

      const c = canvas.getContext("2d")
      if (!c) return

      c.setTransform(dpr, 0, 0, dpr, 0, 0)
      c.clearRect(0, 0, width, height)

      const revealX = plot.x + plot.width * reveal

      c.save()
      c.beginPath()
      c.rect(plot.x, plot.y, Math.max(0, revealX - plot.x), plot.height)
      c.clip()

      const keys = series.map((s) => s.dataKey)
      const layers =
        stackType === "stacked" && chartKind !== "line"
          ? stackSeries(data, keys)
          : null

      series.forEach((entry, seriesIndex) => {
        const color = resolveColor(config[entry.dataKey]?.color, entry.dataKey)
        const angles = anglesForSeries(seriesIndex)

        if (entry.kind === "bar" || chartKind === "bar") {
          drawBars(c, {
            data,
            dataKey: entry.dataKey,
            keys,
            layers,
            stackType,
            xScale,
            yScale,
            xKey: xAxis.dataKey,
            color,
            angles,
            reveal,
          })
          return
        }

        const curves = buildCurveLookup({
          data,
          dataKey: entry.dataKey,
          keys,
          layers,
          stackType,
          xScale,
          yScale,
          xKey: xAxis.dataKey,
        })

        const isLine = entry.kind === "line" || chartKind === "line"
        const depth = isLine
          ? Math.max(12, plot.height * 0.08)
          : Math.max(18, plot.height * 0.14)

        c.save()
        traceAreaPath(
          c,
          data,
          xAxis.dataKey,
          xScale,
          curves.yTop,
          curves.yBase
        )
        c.clip()
        hatch(c, plot, toneBetweenCurves(curves.yTop, curves.yBase, depth), {
          angles,
          color,
          alpha: reveal,
        })
        c.restore()
      })

      c.restore()
    },
    [
      width,
      height,
      plot,
      data,
      series,
      config,
      stackType,
      chartKind,
      xScale,
      yScale,
      xAxis.dataKey,
    ]
  )

  useEffect(() => {
    if (!animate || prefersReducedMotion()) {
      progressRef.current = 1
      drawFrame(1)
      return
    }

    progressRef.current = 0
    startRef.current = null

    const tick = (now: number) => {
      if (startRef.current == null) startRef.current = now
      const elapsed = now - startRef.current
      const t = Math.min(1, elapsed / REVEAL_MS)
      progressRef.current = easeOutCubic(t)
      drawFrame(progressRef.current)
      if (t < 1) {
        rafRef.current = requestAnimationFrame(tick)
      }
    }

    rafRef.current = requestAnimationFrame(tick)

    return () => {
      if (rafRef.current != null) cancelAnimationFrame(rafRef.current)
    }
  }, [animate, drawFrame])

  useEffect(() => {
    if (!animate || progressRef.current >= 1) {
      drawFrame(progressRef.current)
    }
  }, [drawFrame, animate])

  const handlePointer = useCallback(
    (clientX: number) => {
      const canvas = canvasRef.current
      if (!canvas) return
      const rect = canvas.getBoundingClientRect()
      const x = clientX - rect.left
      if (x < plot.x || x > plot.x + plot.width) {
        setHoverIndex(null)
        return
      }
      setHoverIndex(indexAtX(data, xAxis.dataKey, xScale, x))
    },
    [data, plot, setHoverIndex, xAxis.dataKey, xScale]
  )

  const onMouseMove = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      handlePointer(e.clientX)
    },
    [handlePointer]
  )

  const onMouseLeave = useCallback(() => {
    setHoverIndex(null)
  }, [setHoverIndex])

  return (
    <canvas
      ref={canvasRef}
      className="absolute inset-0 block h-full w-full"
      aria-hidden
      onMouseMove={onMouseMove}
      onMouseLeave={onMouseLeave}
    />
  )
}

type DrawBarsOpts = {
  data: ChartDatum[]
  dataKey: string
  keys: string[]
  layers: Array<Map<number, [number, number]>> | null
  stackType: "default" | "stacked"
  xScale: ScaleBand<string> | ScalePoint<string>
  yScale: (v: number) => number
  xKey: string
  color: [number, number, number]
  angles: number[]
  reveal: number
}

function drawBars(
  c: CanvasRenderingContext2D,
  opts: DrawBarsOpts
): void {
  const {
    data,
    dataKey,
    keys,
    layers,
    stackType,
    xScale,
    yScale,
    xKey,
    color,
    angles,
    reveal,
  } = opts

  const bandwidth =
    "bandwidth" in xScale && typeof xScale.bandwidth === "function"
      ? xScale.bandwidth()
      : 16
  const barWidth = Math.max(4, bandwidth * 0.72)

  data.forEach((row, i) => {
    const label = String(row[xKey] ?? "")
    const cx = xCenter(xScale, label)
    const { baseline, top } = valueAtIndex(
      data,
      keys,
      stackType,
      i,
      dataKey
    )
    const yTop = yScale(top)
    const yBase = yScale(baseline)
    const left = cx - barWidth / 2

    c.save()
    c.beginPath()
    c.rect(left, yTop, barWidth, yBase - yTop)
    c.clip()
    hatch(
      c,
      { x: left, y: yTop, width: barWidth, height: yBase - yTop },
      toneBlock(yTop, yBase),
      { angles, color, alpha: reveal }
    )
    c.restore()
  })
}

type CurveLookupOpts = {
  data: ChartDatum[]
  dataKey: string
  keys: string[]
  layers: Array<Map<number, [number, number]>> | null
  stackType: "default" | "stacked"
  xScale: ScaleBand<string> | ScalePoint<string>
  yScale: (v: number) => number
  xKey: string
}

type CurveLookup = {
  yTop: (x: number) => number
  yBase: (x: number) => number
}

function buildCurveLookup(opts: CurveLookupOpts): CurveLookup {
  const { data, dataKey, keys, layers, stackType, xScale, yScale, xKey } =
    opts
  const points = data.map((row, i) => {
    const label = String(row[xKey] ?? "")
    const cx = xCenter(xScale, label)
    let top = numeric(row, dataKey)
    let base = 0
    if (stackType === "stacked" && layers) {
      const keyIndex = keys.indexOf(dataKey)
      const pair = layers[keyIndex]?.get(i) ?? [0, top]
      base = pair[0]
      top = pair[1]
    }
    return { x: cx, yTop: yScale(top), yBase: yScale(base) }
  })

  const interpolate = (
    pick: (p: (typeof points)[number]) => number
  ): ((x: number) => number) => {
    return (x: number) => {
      if (points.length === 0) return yScale(0)
      if (x <= points[0].x) return pick(points[0])
      if (x >= points[points.length - 1].x) return pick(points[points.length - 1])

      for (let i = 0; i < points.length - 1; i++) {
        const a = points[i]
        const b = points[i + 1]
        if (x >= a.x && x <= b.x) {
          const t = (x - a.x) / Math.max(1e-6, b.x - a.x)
          return pick(a) + (pick(b) - pick(a)) * t
        }
      }
      return pick(points[points.length - 1])
    }
  }

  return {
    yTop: interpolate((p) => p.yTop),
    yBase: interpolate((p) => p.yBase),
  }
}

function toneBetweenCurves(
  yTop: (x: number) => number,
  yBase: (x: number) => number,
  depth: number
) {
  return (x: number, y: number) => {
    const top = yTop(x)
    const base = yBase(x)
    if (y < top || y > base) return 0
    const span = base - top
    if (span <= 0) return 1
    const effectiveDepth = Math.min(depth, span)
    const i = (y - top) / effectiveDepth
    return i > 1 ? 1 : i
  }
}

function traceAreaPath(
  c: CanvasRenderingContext2D,
  data: ChartDatum[],
  xKey: string,
  xScale: ScaleBand<string> | ScalePoint<string>,
  yTop: (x: number) => number,
  yBase: (x: number) => number
): void {
  if (data.length === 0) return

  const first = String(data[0][xKey] ?? "")
  const last = String(data[data.length - 1][xKey] ?? "")
  const x0 = xCenter(xScale, first)
  const x1 = xCenter(xScale, last)

  c.beginPath()
  c.moveTo(x0, yTop(x0))
  for (let i = 1; i < data.length; i++) {
    const label = String(data[i][xKey] ?? "")
    const x = xCenter(xScale, label)
    c.lineTo(x, yTop(x))
  }
  c.lineTo(x1, yBase(x1))
  for (let i = data.length - 2; i >= 0; i--) {
    const label = String(data[i][xKey] ?? "")
    const x = xCenter(xScale, label)
    c.lineTo(x, yBase(x))
  }
  c.closePath()
}

/**
 * The burin. Everything else in this kit is scaffolding around this file.
 *
 * A copperplate engraver has no grey ink. Tone comes from line work: lines cut
 * closer together and, crucially, cut *deeper* — a deeper cut holds more ink and
 * prints wider. One continuous line therefore swells and tapers along its length
 * as it crosses light and dark passages. That swell is the whole tell. It is what
 * separates an engraving from a sketch, and it's why a hand-drawn chart library
 * (rough.js and friends) can't get here: their lines wobble, and wobble reads as
 * pencil, not steel.
 *
 * So: straight lines, zero jitter, width modulated by local tone.
 */

export type Rgb = [number, number, number]

/** Tone at a point: 0 at the top of the fill, 1 deep in it. */
export type ToneFn = (x: number, y: number) => number

export type HatchOpts = {
  /** Hatch angles in degrees. Two entries = cross-hatch. */
  angles: number[]
  /** Perpendicular gap between neighbouring lines, in px. */
  spacing?: number
  /** Sampling step along each line, in px. Smaller = smoother swell, slower. */
  step?: number
  /** Line width at zero tone and at full tone. */
  minWidth?: number
  maxWidth?: number
  /** Tone below this is left as bare paper. */
  floor?: number
  color: Rgb
  /** 0-1, scales every line width — used for the entrance reveal. */
  alpha?: number
}

const DEG = Math.PI / 180

export const rgb = ([r, g, b]: Rgb, a = 1) =>
  a >= 1 ? `rgb(${r},${g},${b})` : `rgba(${r},${g},${b},${a})`

/**
 * Series 1 hatches one way, series 2 the other, series 3+ cross-hatch. Overlapping
 * fills stay separable because their line directions differ, which is exactly the
 * trick 19th-century engravers used to keep adjacent objects legible in one ink.
 */
export function anglesForSeries(index: number): number[] {
  switch (index % 3) {
    case 0:
      return [-38]
    case 1:
      return [38]
    default:
      return [-38, 38]
  }
}

/**
 * Lay hatch across the current clip region.
 *
 * Walks a lattice of parallel lines in rotated space and maps each sample back to
 * screen space, so the lines stay dead straight regardless of angle. Width is
 * re-evaluated every `step` px from `tone`, which is what produces the swell.
 *
 * The caller owns the clip: set it to the fill path (an area, a bar) before
 * calling. Nothing here knows what shape it is filling.
 */
export function hatch(
  c: CanvasRenderingContext2D,
  bounds: { x: number; y: number; width: number; height: number },
  tone: ToneFn,
  opts: HatchOpts
): void {
  const {
    angles,
    spacing = 5,
    step = 2.2,
    minWidth = 0.35,
    maxWidth = 2.0,
    floor = 0.04,
    color,
    alpha = 1,
  } = opts

  if (alpha <= 0) return

  const { x: bx, y: by, width: bw, height: bh } = bounds
  const cx = bx + bw / 2
  const cy = by + bh / 2
  // Half-diagonal: far enough that a line at any angle still spans the bounds.
  const reach = Math.hypot(bw, bh) / 2 + spacing

  c.save()
  c.lineCap = "round"
  c.strokeStyle = rgb(color)

  for (const deg of angles) {
    const cos = Math.cos(deg * DEG)
    const sin = Math.sin(deg * DEG)

    for (let off = -reach; off <= reach; off += spacing) {
      // One straight line. `t` runs along it; `off` steps across the lattice.
      for (let t = -reach; t < reach; t += step) {
        const x1 = cx + t * cos - off * sin
        const y1 = cy + t * sin + off * cos
        if (x1 < bx || x1 > bx + bw || y1 < by || y1 > by + bh) continue

        const i = tone(x1, y1)
        if (i <= floor) continue

        const x2 = cx + (t + step) * cos - off * sin
        const y2 = cy + (t + step) * sin + off * cos

        c.lineWidth = (minWidth + i * (maxWidth - minWidth)) * alpha
        c.beginPath()
        c.moveTo(x1, y1)
        c.lineTo(x2, y2)
        c.stroke()
      }
    }
  }

  c.restore()
}

/**
 * Tone that deepens with distance below a curve — the default for area fills.
 * `depth` is how far below the line the ink reaches full black; shallower values
 * make a heavier, flatter fill.
 */
export function toneBelowCurve(
  yAt: (x: number) => number,
  baseline: number,
  depth: number
): ToneFn {
  return (x, y) => {
    const top = yAt(x)
    if (y < top || y > baseline) return 0
    const i = (y - top) / depth
    return i > 1 ? 1 : i
  }
}

/** Flat tone across a shape (bars), with a slight gradient so it isn't dead. */
export function toneBlock(top: number, bottom: number, lift = 0.35): ToneFn {
  const span = Math.max(1, bottom - top)
  return (_x, y) => {
    if (y < top || y > bottom) return 0
    return lift + (1 - lift) * ((y - top) / span)
  }
}

export const clamp01 = (t: number) => (t < 0 ? 0 : t > 1 ? 1 : t)
export const easeOutCubic = (t: number) => 1 - (1 - t) ** 3

export function prefersReducedMotion(): boolean {
  return (
    typeof window !== "undefined" &&
    window.matchMedia?.("(prefers-reduced-motion: reduce)").matches === true
  )
}

/** Backing-store size for a crisp canvas on retina, capped so huge charts
 * don't allocate absurd buffers. */
export function backingSize(width: number, height: number, cap = 2) {
  const dpr = Math.min(
    typeof window !== "undefined" ? window.devicePixelRatio || 1 : 1,
    cap
  )
  return { width: Math.round(width * dpr), height: Math.round(height * dpr), dpr }
}

"use client"

import { useMemo } from "react"
import { useChartContext } from "./chart-context"

export function Grid() {
  const { plot, yScale, yAxis } = useChartContext()

  const ticks = useMemo(
    () => yScale.ticks(yAxis.tickCount),
    [yScale, yAxis.tickCount]
  )

  return (
    <g className="engrave-grid">
      {ticks.map((tick) => {
        const y = yScale(tick)
        return (
          <line
            key={tick}
            x1={plot.x}
            x2={plot.x + plot.width}
            y1={y}
            y2={y}
            stroke="var(--foreground, #181816)"
            strokeWidth={1}
            opacity={0.08}
            strokeDasharray="2 4"
          />
        )
      })}
    </g>
  )
}

"use client"

import { useMemo } from "react"
import { useChartContext } from "./chart-context"
import { resolveColor } from "./palette"

export function Legend() {
  const { series, config, plot } = useChartContext()

  const items = useMemo(
    () =>
      series.map((entry) => {
        const rgb = resolveColor(config[entry.dataKey]?.color, entry.dataKey)
        const label = config[entry.dataKey]?.label ?? entry.dataKey
        return { key: entry.dataKey, label, rgb }
      }),
    [series, config]
  )

  if (items.length === 0) return null

  return (
    <foreignObject
      x={plot.x}
      y={plot.y - 28}
      width={plot.width}
      height={24}
    >
      <div className="flex flex-wrap items-center justify-end gap-3 text-[11px] text-[var(--muted-foreground,#6b7280)]">
        {items.map((item) => (
          <span key={item.key} className="inline-flex items-center gap-1.5">
            <span
              className="inline-block h-2 w-2 rounded-full"
              style={{ backgroundColor: `rgb(${item.rgb.join(",")})` }}
            />
            {item.label}
          </span>
        ))}
      </div>
    </foreignObject>
  )
}

import type { Rgb } from "./engrave-paint"

export type EngraveColor = "ink" | "crimson" | "indigo" | "moss" | "ochre" | "slate"

export const PALETTE: Record<EngraveColor, Rgb> = {
  ink: [18, 18, 22],
  crimson: [120, 28, 36],
  indigo: [36, 44, 92],
  moss: [48, 72, 44],
  ochre: [148, 108, 36],
  slate: [72, 80, 92],
}

/** Stable pseudo-random pick from the ink drawer for unconfigured series. */
export function seedOf(key: string): EngraveColor {
  const colors = Object.keys(PALETTE) as EngraveColor[]
  let h = 0
  for (let i = 0; i < key.length; i++) {
    h = (h * 31 + key.charCodeAt(i)) >>> 0
  }
  return colors[h % colors.length]
}

export function resolveColor(
  name: EngraveColor | undefined,
  dataKey: string
): Rgb {
  return PALETTE[name ?? seedOf(dataKey)]
}

import { scaleBand, scaleLinear, scalePoint } from "d3-scale"
import { stack as d3Stack, stackOffsetNone } from "d3-shape"
import type { ScaleBand, ScaleLinear, ScalePoint } from "d3-scale"

export type ChartDatum = Record<string, string | number | null | undefined>

export type StackType = "default" | "stacked"

export type PlotRect = {
  x: number
  y: number
  width: number
  height: number
}

export type Margins = {
  top: number
  right: number
  bottom: number
  left: number
}

export const DEFAULT_MARGINS: Margins = {
  top: 16,
  right: 16,
  bottom: 32,
  left: 44,
}

export function plotRect(
  width: number,
  height: number,
  margins: Margins
): PlotRect {
  return {
    x: margins.left,
    y: margins.top,
    width: Math.max(0, width - margins.left - margins.right),
    height: Math.max(0, height - margins.top - margins.bottom),
  }
}

export function createXBandScale(
  data: ChartDatum[],
  dataKey: string,
  range: [number, number]
): ScaleBand<string> {
  return scaleBand<string>()
    .domain(data.map((d) => String(d[dataKey] ?? "")))
    .range(range)
    .padding(0.2)
}

export function createXPointScale(
  data: ChartDatum[],
  dataKey: string,
  range: [number, number]
): ScalePoint<string> {
  // No padding: an area or line must reach both plot edges. Inset the endpoints
  // and the fill stops short of the axis, which reads as a clipping bug.
  return scalePoint<string>()
    .domain(data.map((d) => String(d[dataKey] ?? "")))
    .range(range)
    .padding(0)
}

export function createYLinearScale(
  domain: [number, number],
  range: [number, number]
): ScaleLinear<number, number> {
  const [min, max] = domain
  const paddedMax = max === min ? max + 1 : max
  return scaleLinear<number, number>()
    .domain([Math.min(0, min), paddedMax])
    .range(range)
    .nice()
}

function numericValue(d: ChartDatum, key: string): number {
  const v = d[key]
  return typeof v === "number" && Number.isFinite(v) ? v : 0
}

export function yExtent(
  data: ChartDatum[],
  keys: string[],
  stackType: StackType
): [number, number] {
  if (keys.length === 0) return [0, 1]

  if (stackType === "stacked") {
    const layers = stackSeries(data, keys)
    let min = 0
    let max = 0
    for (const layer of layers) {
      for (const [, pair] of layer) {
        min = Math.min(min, pair[0])
        max = Math.max(max, pair[1])
      }
    }
    return [min, max]
  }

  let min = 0
  let max = 0
  for (const row of data) {
    for (const key of keys) {
      const v = numericValue(row, key)
      min = Math.min(min, v)
      max = Math.max(max, v)
    }
  }
  return [min, max]
}

export type StackLayer = {
  key: string
  points: Array<[number, number]>
}

export function stackSeries(
  data: ChartDatum[],
  keys: string[]
): Array<Map<number, [number, number]>> {
  const layers = d3Stack<ChartDatum>()
    .keys(keys)
    .offset(stackOffsetNone)(data)

  return layers.map((layer) => {
    const map = new Map<number, [number, number]>()
    layer.forEach((row, i) => {
      map.set(i, [row[0], row[1]])
    })
    return map
  })
}

export function valueAtIndex(
  data: ChartDatum[],
  keys: string[],
  stackType: StackType,
  index: number,
  key: string
): { value: number; baseline: number; top: number } {
  const row = data[index]
  if (!row) return { value: 0, baseline: 0, top: 0 }

  const value = numericValue(row, key)

  if (stackType === "stacked") {
    const keyIndex = keys.indexOf(key)
    const layers = stackSeries(data, keys)
    const layer = layers[keyIndex]
    const pair = layer?.get(index) ?? [0, value]
    return { value: pair[1] - pair[0], baseline: pair[0], top: pair[1] }
  }

  return { value, baseline: 0, top: value }
}

export function xCenter(
  scale: ScaleBand<string> | ScalePoint<string>,
  label: string
): number {
  const x = scale(label)
  if (x == null) return 0
  if ("bandwidth" in scale && typeof scale.bandwidth === "function") {
    return x + scale.bandwidth() / 2
  }
  return x
}

"use client"

import { useEffect } from "react"
import { useChartContext, type SeriesKind } from "./chart-context"

export type SeriesProps = {
  dataKey: string
}

function useSeriesRegistration(dataKey: string, kind: SeriesKind) {
  const { registerSeries, unregisterSeries } = useChartContext()

  useEffect(() => {
    registerSeries({ dataKey, kind })
    return () => {
      unregisterSeries(dataKey)
    }
  }, [dataKey, kind, registerSeries, unregisterSeries])

  return null
}

export function Area({ dataKey }: SeriesProps) {
  useSeriesRegistration(dataKey, "area")
  return null
}

export function Line({ dataKey }: SeriesProps) {
  useSeriesRegistration(dataKey, "line")
  return null
}

export function Bar({ dataKey }: SeriesProps) {
  useSeriesRegistration(dataKey, "bar")
  return null
}

"use client"

import { useMemo } from "react"
import { useChartContext } from "./chart-context"
import { xCenter } from "./scales"

export type TooltipProps = {
  labelKey?: string
  valueFormatter?: (value: number, dataKey: string) => string
}

export function Tooltip({
  labelKey,
  valueFormatter = (v) => String(Math.round(v * 10) / 10),
}: TooltipProps) {
  const { data, series, config, hoverIndex, plot, xScale, xAxis } =
    useChartContext()

  const active = hoverIndex != null ? data[hoverIndex] : null
  const labelField = labelKey ?? xAxis.dataKey

  const crosshairX = useMemo(() => {
    if (hoverIndex == null || !active) return null
    const label = String(active[labelField] ?? "")
    return xCenter(xScale, label)
  }, [hoverIndex, active, labelField, xScale])

  if (hoverIndex == null || !active || crosshairX == null) return null

  return (
    <>
      <line
        x1={crosshairX}
        x2={crosshairX}
        y1={plot.y}
        y2={plot.y + plot.height}
        stroke="var(--foreground, #181816)"
        strokeWidth={1}
        opacity={0.2}
        strokeDasharray="3 3"
      />
      <foreignObject
        x={Math.min(crosshairX + 8, plot.x + plot.width - 140)}
        y={plot.y + 8}
        width={140}
        height={120}
      >
        <div className="rounded border border-[var(--border,#e5e7eb)] bg-[var(--background,#fff)] px-2 py-1.5 text-[11px] shadow-sm">
          <div className="mb-1 font-medium text-[var(--foreground,#181816)]">
            {String(active[labelField] ?? "")}
          </div>
          {series.map((entry) => {
            const raw = active[entry.dataKey]
            const value = typeof raw === "number" ? raw : 0
            const label = config[entry.dataKey]?.label ?? entry.dataKey
            return (
              <div
                key={entry.dataKey}
                className="flex justify-between gap-3 text-[var(--muted-foreground,#6b7280)]"
              >
                <span>{label}</span>
                <span className="tabular-nums text-[var(--foreground,#181816)]">
                  {valueFormatter(value, entry.dataKey)}
                </span>
              </div>
            )
          })}
        </div>
      </foreignObject>
    </>
  )
}

"use client"

import { useCallback, useEffect, useRef, useState } from "react"

export type ChartDimensions = {
  width: number
  height: number
}

export function useChartDimensions<T extends HTMLElement = HTMLDivElement>() {
  const ref = useRef<T | null>(null)
  const [dimensions, setDimensions] = useState<ChartDimensions>({
    width: 0,
    height: 0,
  })

  const measure = useCallback(() => {
    const node = ref.current
    if (!node) return
    const rect = node.getBoundingClientRect()
    const nextWidth = Math.round(rect.width)
    const nextHeight = Math.round(rect.height)
    setDimensions((prev) =>
      prev.width === nextWidth && prev.height === nextHeight
        ? prev
        : { width: nextWidth, height: nextHeight }
    )
  }, [])

  useEffect(() => {
    const node = ref.current
    if (!node) return

    measure()

    const observer = new ResizeObserver(() => {
      measure()
    })
    observer.observe(node)

    return () => {
      observer.disconnect()
    }
  }, [measure])

  return { ref, ...dimensions }
}
